// client/src/components/ResultDisplay.js
import React from 'react';
import { Alert, Badge } from 'react-bootstrap';

const ResultDisplay = ({ result }) => {
  if (!result) {
    return (
      <div className="result-container text-center text-muted">
        <p>Enter text and click "Analyze Sentiment" to see results</p>
      </div>
    );
  }

  const { sentiment, score, text, type, explanation } = result;

  // Helper function to format score for display
  const formatScore = (score) => {
    return (score * 10).toFixed(2);
  };

  const getSentimentEmoji = () => {
    switch (sentiment) {
      case 'positive':
        return '😊';
      case 'negative':
        return '😞';
      default:
        return '😐';
    }
  };

  // Get type-specific icon
  const getTypeIcon = () => {
    switch (type) {
      case 'emotional':
        return '❤️';
      case 'date':
        return '📅';
      case 'math':
        return '🔢';
      case 'historical':
        return '📚';
      default:
        return '📝';
    }
  };

  return (
    <div className="result-container">
      <div className={`sentiment-badge ${sentiment}`}>
        {sentiment.toUpperCase()} {getSentimentEmoji()}
      </div>
      
      <div className="result-score">
        {formatScore(score)}
      </div>
      
      <Badge bg="info" className="mb-3">
        {getTypeIcon()} {type.charAt(0).toUpperCase() + type.slice(1)} Analysis
      </Badge>
      
      {explanation && (
        <Alert variant="info" className="mt-2 mb-3">
          <small className="fw-bold">Explanation:</small>
          <p className="mb-0">{explanation}</p>
        </Alert>
      )}
      
      <Alert variant="light" className="mt-1">
        <small className="text-muted">Analyzed text:</small>
        <p className="mb-0">"{text}"</p>
      </Alert>
    </div>
  );
};

export default ResultDisplay;
